    while(T--) {
        int N; cin>>N;
        long long max_sum = LLONG_MIN, current_sum = 0;
        for(int i=0;i<N;++i){
            long long x; cin>>x;
            if(i==0){current_sum=x; max_sum=x;}
            else{
                current_sum = max(x, current_sum + x);
                max_sum = max(max_sum, current_sum);
            }
        }
        cout<<max_sum<<"\n";
    }
    return 0;
}

