import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        max_sum = -10**18
        cur = 0
        for i in range(N):
            x = int(next(it))
            if i == 0:
                cur = x
                max_sum = x
            else:
                cur = max(x, cur + x)
                if cur > max_sum:
                    max_sum = cur
        out_lines.append(str(max_sum))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

